41	const CATEGORY_FALLBACK_COLOR_HEX = '#cbd5e1';
42	
43	function categoryColorOr(bundle: ViewportPaintBundle | null, cat: ElementCategoryToken): string {
44	  return bundle?.categories[cat]?.color ?? CATEGORY_FALLBACK_COLOR_HEX;
45	}
46	
47	function readToken(name: string, fallback: string): string {
48	  const v = liveTokenReader().read(name);
49	  return v && v.trim().length > 0 ? v : fallback;
50	}
51	
52	/** Resolve a CSS color token to an rgb() string that Three.js can parse.
53	 * CSS Color Level 4 hsl() uses spaces (e.g. "hsl(0 0% 100%)") which
54	 * Three.js does not support — routing through a DOM element forces the
55	 * browser to resolve it to "rgb(r, g, b)". */
56	function readColorToken(name: string, fallback: string): string {
57	  if (typeof document === 'undefined') return fallback;
58	  try {
59	    const el = document.createElement('div');
60	    el.style.display = 'none';
61	    el.style.color = `var(${name}, ${fallback})`;
62	    document.body.appendChild(el);
63	    const resolved = getComputedStyle(el).color;
64	    document.body.removeChild(el);
65	    return resolved || fallback;
66	  } catch {
67	    return fallback;
68	  }
69	}
70	
71	function sunPositionFromAzEl(azimuthDeg: number, elevationDeg: number, radiusM = 80): THREE.Vector3 {
72	  const az = THREE.MathUtils.degToRad(azimuthDeg);
73	  const el = THREE.MathUtils.degToRad(elevationDeg);
74	  return new THREE.Vector3(
75	    radiusM * Math.cos(el) * Math.sin(az),
76	    radiusM * Math.sin(el),
77	    radiusM * Math.cos(el) * Math.cos(az),
78	  );
79	}
80	
81	function buildSkyEnvMap(
82	  renderer: THREE.WebGLRenderer,
83	  azimuthDeg: number,
84	  elevationDeg: number,
85	): THREE.Texture {
86	  const sky = new Sky();
87	  sky.scale.setScalar(450000);
88	  const u = sky.material.uniforms;
89	  u['turbidity'].value = 3;
